import{_ as i,o as a,c as n,a as e}from"./chunks/framework.8tiMeCK-.js";const c=JSON.parse('{"title":"1.7  打造你的定制生产内核","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch01_6.md","filePath":"notes/linux_kernel_debugging/ch01_6.md","lastUpdated":null}'),p={name:"notes/linux_kernel_debugging/ch01_6.md"};function l(t,s,r,h,d,o){return a(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="_1-7-打造你的定制生产内核" tabindex="-1">1.7 打造你的定制生产内核 <a class="header-anchor" href="#_1-7-打造你的定制生产内核" aria-label="Permalink to &quot;1.7  打造你的定制生产内核&quot;">​</a></h1><p>到了这一步，我必须假设你对从源码构建 Linux 内核的这套「基本操作」已经不算陌生了：拉取源码树、配置、编译。如果你觉得有点生疏，或者想复习一下细节，强烈推荐去翻翻《Linux Kernel Programming》这本书，或者参考本章末尾的「延伸阅读」部分。</p><p>既然说是「生产内核」，我们的目标就很明确：它得稳，得快，得安全。但就像我们在上一节讨论的，不能从零开始瞎猜配置。最聪明的办法是「站在巨人的肩膀上」——基于现有系统的配置进行调优（这就是所谓的 <code>localmodconfig</code> 策略）。一旦有了这个靠谱的起点，我们再通过「加固」配置来提升安全性。</p><p>让我们开始第一步，先把地基打好。</p><h3 id="_1-7-1-获取源码与基础配置" tabindex="-1">1.7.1 获取源码与基础配置 <a class="header-anchor" href="#_1-7-1-获取源码与基础配置" aria-label="Permalink to &quot;1.7.1  获取源码与基础配置&quot;">​</a></h3><p><strong>目标</strong>：建立工作目录，拉取并解压 LTS 内核源码。</p><blockquote><p><strong>为什么这样做</strong>： 上一节我们选定了 <strong>5.10.60</strong> 这个 LTS 版本作为基准。为了保持环境整洁，我们需要一个独立的工作目录来存放源码和编译产物。<code>tar</code> 的 <code>--directory</code> 参数能让我们在解压的同时把文件归位，少敲几行 <code>mv</code>。</p></blockquote><p><strong>操作位置</strong>：用户主目录</p><p><strong>命令与输出</strong>：</p><p>首先，咱们建个专门的「车间」：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> –p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/productionk</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>接下来把源码拉下来。这里我们用的是 <code>wget</code> 直接抓取压缩包，当然你也可以用 <code>git</code>（如果你不介意等待的时间稍微长一点）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://mirrors.edge.kernel.org/pub/linux/kernel/v5.x/linux-5.10.60.tar.xz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>解压它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linux-5.10.60.tar.xz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --directory=productionk/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>进入解压后的目录，顺手验证一下版本信息。这看起来是个无聊的步骤，但有一件事挺有意思：</p><p>每个版本的 Linux 内核都有一个「代号」—— 5.10.60 的代号是 <strong>&quot;Dare mighty things&quot;</strong>（敢于成就大事）。我挺喜欢这个名字的，它放在这里非常应景，毕竟我们正在做的事，就是在操作系统的核心地带动刀子。</p><h3 id="_1-7-2-生成精简配置-localmodconfig" tabindex="-1">1.7.2 生成精简配置（localmodconfig） <a class="header-anchor" href="#_1-7-2-生成精简配置-localmodconfig" aria-label="Permalink to &quot;1.7.2  生成精简配置（localmodconfig）&quot;">​</a></h3><p><strong>目标</strong>：利用当前系统正在运行的模块列表，生成一个量身定制的初始内核配置文件。</p><blockquote><p><strong>为什么这样做</strong>： 全量默认配置包含了几千个你用不到的驱动和模块，编译出来的内核既臃肿又慢。<code>localmodconfig</code> 的魔法在于，它会扫描当前系统加载了哪些模块（<code>lsmod</code> 的结果），然后把没选中的东西统统关掉。这就好比给内核做了一次抽脂手术。</p></blockquote><p><strong>操作位置</strong>：内核源码根目录 (<code>~/lkd_kernels/productionk/linux-5.10.60/</code>)</p><p><strong>命令与输出</strong>：</p><p>先生成一份当前系统的模块快照：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/lsmod.now</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后把这个快照喂给 <code>make</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LSMOD=/tmp/lsmod.now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localmodconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>⚠️ 踩坑预警</strong> 这个过程中，终端可能会停下来问你几个问题（交互式界面）。别慌，如果你不懂某个选项的具体含义，<strong>直接按 Enter 键选默认值</strong>通常是最安全的。我们的目标只是获得一个「够用」的起点，而不是在这里这就把所有细节都敲定。</p><p>这步做完之后，源码树根目录下就多了一个 <code>.config</code> 文件。这可是宝贝，它是内核的「灵魂」。</p><p>先把它备份起来，以防后面改坏了回不来：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> –af</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/kconfig_prod01</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>小贴士</strong>：随时可以敲 <code>make help</code> 查看所有可用的配置命令。如果你是个老手，完全可以用 <code>make menuconfig</code> 进去把界面改成你熟悉的风格。</p></blockquote><h3 id="_1-7-3-内核加固——安全的代价" tabindex="-1">1.7.3 内核加固——安全的代价 <a class="header-anchor" href="#_1-7-3-内核加固——安全的代价" aria-label="Permalink to &quot;1.7.3  内核加固——安全的代价&quot;">​</a></h3><p><strong>目标</strong>：通过自动化工具检查并修改内核配置，开启安全加固选项。</p><p>现在我们有一个「能跑」的配置了。但在把它投入生产之前，我们要解决一个两难问题：<strong>安全 vs 便利</strong>。</p><p>很多加固特性在 Linux 内核里默认是<strong>关闭</strong>的。为什么？因为它们要么会牺牲性能，要么会破坏某些旧软件的兼容性。但在生产环境中，尤其是对于专门用来调试或运行敏感服务的系统，我们倾向于选择「安全」。</p><p>问题是：哪怕你打开 <code>make menuconfig</code>，面对成千上万条选项，你也不知道哪条是管安全的。</p><p>好在有人帮我们干了这个脏活。</p><p><strong>引入工具：kconfig-hardened-check</strong></p><p>这其实是一个验证器——但它能反向告诉你：你的配置里缺了哪些业界公认的安全最佳实践。它就像一个严格的安全审计员，拿着一张检查表（Checklist）对你的 <code>.config</code> 挨个打勾。</p><p>安装并运行它（这里以 Python 脚本为例）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 假设你已经通过 pip 安装了该脚本，或者克隆了仓库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kconfig-hardened-check.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>你会看到一大堆输出，像这样（截取了一部分）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[+] Check: CONFIG_BUG is required: set to y</span></span>
<span class="line"><span>[+] Check: CONFIG_STRICT_KERNEL_RWX is required: set to y</span></span>
<span class="line"><span>[-] Check: CONFIG_DEBUG_LIST is suggested: NOT set (should be y)</span></span>
<span class="line"><span>[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>我们不需要在这里深入解释这个脚本的每一个细节（那值得单独写一篇文章），核心逻辑是：<strong>它告诉你缺什么，你就补什么</strong>。</p><p>我根据它的建议，调整出了生产内核的最终配置。这个配置文件我已经放到了本书的 GitHub 仓库里（<code>ch1/kconfig_prod01</code>），你可以直接拿去用，或者作为参考。</p><h3 id="_1-7-4-编译与安装" tabindex="-1">1.7.4 编译与安装 <a class="header-anchor" href="#_1-7-4-编译与安装" aria-label="Permalink to &quot;1.7.4  编译与安装&quot;">​</a></h3><p><strong>目标</strong>：编译内核，安装模块，并更新引导加载程序。</p><p>现在，配置终于定稿了。是时候把这些源代码变成那个著名的 <strong>bzImage</strong> 了。</p><p><strong>操作位置</strong>：内核源码根目录</p><p>首先，确认一下你的 CPU 核心数，这决定了我们能多快干完这活：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nproc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这里我有 4 个核心。作为经验法则，<code>make -j</code> 后面的数字通常是核心数的 2 倍。这样可以最大化利用 CPU，同时避免过载。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j8</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ ... 一大段滚动的编译日志 ... ]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BUILD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   arch/x86/boot/bzImage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Kernel:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ready</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (#1)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>看到 <code>is ready</code> 这行，你就成功了。</p><p>但这里有两个文件，我们需要稍微理清一下关系：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rw-r--r--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9.1M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 17:21</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rwxr-xr-x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  65M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 17:21</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>bzImage (9.1MB)</strong>：这是<strong>压缩</strong>后的内核镜像。这是 GRUB 实际读取并启动的文件。别被名字里的 <code>b</code> 迷惑，它不代表 Big，而是代表 &quot;boot zImage&quot;（大概）。</li><li><strong>vmlinux (65MB)</strong>：这是<strong>未压缩</strong>的 ELF 可执行文件。<strong>别删它</strong>。虽然启动不用它，但它包含了所有的<strong>符号信息</strong>——那是我们后面调试时的救命稻草。</li></ul><blockquote><p><strong>SICP 式旁白</strong>：这里有一个微妙的分工。<code>bzImage</code> 是为了生存——它要足够小，能被加载进内存并快速解压；<code>vmlinux</code> 是为了理解——它保留了所有的细节，供我们在系统崩溃时尸检。</p></blockquote><p>接下来，安装内核模块。这会把编译好的 <code>.ko</code> 文件拷贝到系统的标准目录 <code>/lib/modules/$(uname -r)</code> 下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modules_install</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ ... ]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  DEPMOD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.10.60-prod01</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /lib/modules/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">5.10.60-prod01/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.11.0-27-generic/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.8.0-43-generic/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>注意看那个 <code>5.10.60-prod01</code> 目录，这就是我们的新地盘。</p><p>最后一步，让系统「知道」这个新内核的存在。我们需要生成 <code>initramfs</code>（初始内存文件系统），并更新 GRUB 配置：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这行命令背后其实运行了好几个脚本。<code>initramfs</code> 非常关键，它包含了一组最基本的驱动和脚本，负责在内核真正挂载硬盘上的根文件系统之前，先把硬件环境准备好。没有它，现代系统通常起不来。</p><h3 id="_1-7-5-第一次点火——切换到新内核" tabindex="-1">1.7.5 第一次点火——切换到新内核 <a class="header-anchor" href="#_1-7-5-第一次点火——切换到新内核" aria-label="Permalink to &quot;1.7.5  第一次点火——切换到新内核&quot;">​</a></h3><p><strong>目标</strong>：重启系统，从 GRUB 菜单选择新内核，验证系统正常运行。</p><p>万事俱备，只欠重启。</p><p>但在按下重启键之前，先停一下。想一想：如果这一步成功了，你预期会看到什么？</p><p>你应该会看到 GRUB 的启动菜单。如果你的菜单平时是隐藏的（或者跳过得太快），你可以在启动时狂按 <strong>Shift 键</strong>（如果是传统 BIOS）或 <strong>Esc 键</strong>（如果是 UEFI），把它叫出来。</p><p>你应该能看到名为 <strong>&quot;5.10.60-prod01&quot;</strong> 的新选项。</p><p>选中它，回车。</p><p>如果你是在虚拟机里操作，比如像我这台 Oracle VirtualBox 一样，可能还会发现一个问题：分辨率不对，或者鼠标不能自动捕获。别担心，那只是因为 VirtualBox 的 <strong>Guest Additions</strong>（客户机附加组件）还没针对新内核编译。这完全不影响内核功能，只是体验上差点意思。为了避免干扰，我通常这时候会直接用 SSH 连进去干活。</p><p>如果一切顺利，你会看到熟悉的登录提示符。</p><p>进系统后，敲下这个命令，确认我们已经坐在了新的引擎上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dbg-LKD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5.10.60-prod01</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #1 SMP PREEMPT Thu Aug 19 17:10:00 IST 2021 x86_64 x86_64 x86_64 GNU/Linux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>那个 <code>5.10.60-prod01</code> 的后缀，就是我们亲手打下的烙印。</p><blockquote><p><strong>阶段性小结</strong> 我们现在有了一个跑在自家定制内核上的系统。它精简、加固、随时待命。但这只是「生产内核」——它就像一个身手敏捷但不爱说话的特工。</p><p>在接下来的旅程中，你会遇到各种棘手的内核级 Bug。有时候，你需要让这个特工开口说话，或者让它把每一步心里活动都记下来。</p><p>那时候，光靠这个「生产内核」是不够的。</p><p>我们还需要另一个更话痨、甚至有点臃肿的角色——<strong>调试内核</strong>。</p></blockquote>`,77)])])}const g=i(p,[["render",l]]);export{c as __pageData,g as default};
